import random

def recursive_loop(sequence):
    for char in sequence:
        yield char

def build_bst(node, value):
    if node is None:
        return Node(value)
    if value < node.value:
        node.left = build_bst(node.left, value)
    else:
        node.right = build_bst(node.right, value)
    return node

class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def main():
    sequence = "abc123def456"
    bst = None
    for char in recursive_loop(sequence):
        lower_char = char.lower()
        if lower_char not in ["a", "b", "c", "d", "e", "f", "g", "h", "i", "j", "k", "l", "m", "n", "o", "p", "q", "r", "s", "t", "u", "v", "w", "x", "y", "z"]:
            bst = build_bst(bst, lower_char)
    print("binary search tree built")

main()

